export function gql(source: "query GetReplyDrafts($status: String, $draftType: String, $limit: Int, $offset: Int) {\n  replyDrafts(\n    status: $status\n    draftType: $draftType\n    limit: $limit\n    offset: $offset\n  ) {\n    drafts {\n      id\n      receivedEmailId\n      contactId\n      status\n      draftType\n      subject\n      bodyText\n      bodyHtml\n      generationModel\n      contactName\n      contactEmail\n      companyName\n      classification\n      classificationConfidence\n      approvedAt\n      sentAt\n      createdAt\n      updatedAt\n    }\n    totalCount\n  }\n}\n\nquery GetDraftSummary {\n  draftSummary {\n    pending\n    approved\n    sent\n    dismissed\n    byClassification {\n      classification\n      count\n    }\n  }\n}\n\nmutation ApproveAndSendDraft($draftId: Int!, $editedSubject: String, $editedBody: String) {\n  approveAndSendDraft(\n    draftId: $draftId\n    editedSubject: $editedSubject\n    editedBody: $editedBody\n  ) {\n    success\n    resendId\n    error\n  }\n}\n\nmutation DismissDraft($draftId: Int!) {\n  dismissDraft(draftId: $draftId) {\n    success\n  }\n}\n\nmutation RegenerateDraft($draftId: Int!, $instructions: String) {\n  regenerateDraft(draftId: $draftId, instructions: $instructions) {\n    id\n    subject\n    bodyText\n    status\n    createdAt\n  }\n}\n\nmutation GenerateDraftsForPending {\n  generateDraftsForPending {\n    success\n    generated\n    skipped\n    failed\n    message\n  }\n}\n\nmutation GenerateFollowUpDrafts($daysAfterInitial: Int, $daysAfterFollowUp1: Int, $daysAfterFollowUp2: Int) {\n  generateFollowUpDrafts(\n    daysAfterInitial: $daysAfterInitial\n    daysAfterFollowUp1: $daysAfterFollowUp1\n    daysAfterFollowUp2: $daysAfterFollowUp2\n  ) {\n    success\n    generated\n    skipped\n    failed\n    message\n  }\n}\n\nmutation ApproveAllDrafts($draftIds: [Int!]!) {\n  approveAllDrafts(draftIds: $draftIds) {\n    success\n    sent\n    failed\n    errors\n  }\n}\n\nmutation DismissAllDrafts($draftIds: [Int!]!) {\n  dismissAllDrafts(draftIds: $draftIds) {\n    success\n    dismissed\n  }\n}"): (typeof documents)["query GetReplyDrafts($status: String, $draftType: String, $limit: Int, $offset: Int) {\n  replyDrafts(\n    status: $status\n    draftType: $draftType\n    limit: $limit\n    offset: $offset\n  ) {\n    drafts {\n      id\n      receivedEmailId\n      contactId\n      status\n      draftType\n      subject\n      bodyText\n      bodyHtml\n      generationModel\n      contactName\n      contactEmail\n      companyName\n      classification\n      classificationConfidence\n      approvedAt\n      sentAt\n      createdAt\n      updatedAt\n    }\n    totalCount\n  }\n}\n\nquery GetDraftSummary {\n  draftSummary {\n    pending\n    approved\n    sent\n    dismissed\n    byClassification {\n      classification\n      count\n    }\n  }\n}\n\nmutation ApproveAndSendDraft($draftId: Int!, $editedSubject: String, $editedBody: String) {\n  approveAndSendDraft(\n    draftId: $draftId\n    editedSubject: $editedSubject\n    editedBody: $editedBody\n  ) {\n    success\n    resendId\n    error\n  }\n}\n\nmutation DismissDraft($draftId: Int!) {\n  dismissDraft(draftId: $draftId) {\n    success\n  }\n}\n\nmutation RegenerateDraft($draftId: Int!, $instructions: String) {\n  regenerateDraft(draftId: $draftId, instructions: $instructions) {\n    id\n    subject\n    bodyText\n    status\n    createdAt\n  }\n}\n\nmutation GenerateDraftsForPending {\n  generateDraftsForPending {\n    success\n    generated\n    skipped\n    failed\n    message\n  }\n}\n\nmutation GenerateFollowUpDrafts($daysAfterInitial: Int, $daysAfterFollowUp1: Int, $daysAfterFollowUp2: Int) {\n  generateFollowUpDrafts(\n    daysAfterInitial: $daysAfterInitial\n    daysAfterFollowUp1: $daysAfterFollowUp1\n    daysAfterFollowUp2: $daysAfterFollowUp2\n  ) {\n    success\n    generated\n    skipped\n    failed\n    message\n  }\n}\n\nmutation ApproveAllDrafts($draftIds: [Int!]!) {\n  approveAllDrafts(draftIds: $draftIds) {\n    success\n    sent\n    failed\n    errors\n  }\n}\n\nmutation DismissAllDrafts($draftIds: [Int!]!) {\n  dismissAllDrafts(draftIds: $draftIds) {\n    success\n    dismissed\n  }\n}"];
